# Tower Defense
import math

class Tower:
    def __init__(self, x, y):
        self.x = x
        self.y = y
        self.level = 1
        self.range = 5
        self.damage = 10

    def upgrade(self):
        self.level += 1
        self.range += 2
        self.damage *= 1.5

    def can_hit(self, enemy):
        dist = math.sqrt(
            (self.x - enemy.x) ** 2 +
            (self.y - enemy.y) ** 2
        )
        return dist <= self.range

    def fire(self, enemy):
        if self.can_hit(enemy):
            enemy.hp -= self.damage
            return True
        return False

class Enemy:
    def __init__(self, hp, speed):
        self.hp = hp
        self.speed = speed
        self.x = 0
        self.y = 0

    def move(self, path):
        self.x += self.speed

    def is_alive(self):
        return self.hp > 0
